import React, { useState, useEffect } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';

function TestHome() {
  const [center, setCenter] = useState([55.751574, 37.573856]);
  const [markers, setMarkers] = useState([]);
  const [selectedMarker, setSelectedMarker] = useState(null);
  const [newMarker, setNewMarker] = useState({ lat: '', lon: '', title: '', type: 'default' });

  // Имитация загрузки из БД
  useEffect(() => {
    // В реальном приложении здесь будет запрос к API
    const savedMarkers = localStorage.getItem('mapMarkers');
    if (savedMarkers) {
      setMarkers(JSON.parse(savedMarkers));
    } else {
      // Демо-данные
      setMarkers([
        { id: 1, lat: 55.751574, lon: 37.573856, title: "Кремль", type: "historic" },
        { id: 2, lat: 55.761574, lon: 37.633856, title: "Парк", type: "park" },
        { id: 3, lat: 55.741574, lon: 37.523856, title: "Торговый центр", type: "shop" },
      ]);
    }
  }, []);

  // Сохранение в "БД" (localStorage для демо)
  const saveMarkers = (updatedMarkers) => {
    setMarkers(updatedMarkers);
    localStorage.setItem('mapMarkers', JSON.stringify(updatedMarkers));

    // В реальном приложении здесь будет запрос на сервер:
    // axios.post('/api/markers', updatedMarkers);
  };

  // Добавление нового маркера
  const handleAddMarker = () => {
    if (!newMarker.lat || !newMarker.lon || !newMarker.title) {
      alert('Заполните все поля');
      return;
    }

    const newMarkerObj = {
      id: Date.now(), // В реальной БД id будет генерироваться сервером
      lat: parseFloat(newMarker.lat),
      lon: parseFloat(newMarker.lon),
      title: newMarker.title,
      type: newMarker.type,
      createdAt: new Date().toISOString()
    };

    const updatedMarkers = [...markers, newMarkerObj];
    saveMarkers(updatedMarkers);

    // Сброс формы
    setNewMarker({ lat: '', lon: '', title: '', type: 'default' });

    // Центрируем карту на новом маркере
    setCenter([newMarkerObj.lat, newMarkerObj.lon]);
  };

  // Удаление маркера
  const handleDeleteMarker = (id) => {
    const updatedMarkers = markers.filter(marker => marker.id !== id);
    saveMarkers(updatedMarkers);
    setSelectedMarker(null);
  };

  // Клик по карте для добавления маркера
  const handleMapClick = (e) => {
    const coords = e.get('coords');
    setNewMarker({
      ...newMarker,
      lat: coords[0].toFixed(6),
      lon: coords[1].toFixed(6)
    });
  };

  // Генерация иконки по типу
  const getIconByType = (type) => {
    const icons = {
      historic: '#FF6B35', // оранжевый
      park: '#4CAF50',     // зеленый
      shop: '#2196F3',     // синий
      cafe: '#FFC107',     // желтый
      default: '#9C27B0'   // фиолетовый
    };

    const color = icons[type] || icons.default;

    const svg = `<svg width="36" height="36" viewBox="0 0 36 36" xmlns="http://www.w3.org/2000/svg">
      <circle cx="18" cy="18" r="16" fill="${color}" fill-opacity="0.9" stroke="white" stroke-width="2"/>
      <circle cx="18" cy="18" r="6" fill="white"/>
    </svg>`;

    return `data:image/svg+xml;base64,${btoa(svg)}`;
  };

  return (
    <div style={{ display: 'flex', gap: '20px', padding: '20px' }}>
      {/* Блок управления */}
      <div style={{ width: '300px', backgroundColor: '#f8f9fa', padding: '20px', borderRadius: '10px' }}>
        <h3 style={{ marginTop: 0 }}>Управление маркерами</h3>

        <div style={{ marginBottom: '20px' }}>
          <h4>Добавить новый маркер</h4>
          <div style={{ marginBottom: '10px' }}>
            <input
              type="text"
              placeholder="Название"
              value={newMarker.title}
              onChange={(e) => setNewMarker({...newMarker, title: e.target.value})}
              style={{ width: '100%', padding: '8px', marginBottom: '8px' }}
            />
            <input
              type="number"
              step="0.000001"
              placeholder="Широта"
              value={newMarker.lat}
              onChange={(e) => setNewMarker({...newMarker, lat: e.target.value})}
              style={{ width: '100%', padding: '8px', marginBottom: '8px' }}
            />
            <input
              type="number"
              step="0.000001"
              placeholder="Долгота"
              value={newMarker.lon}
              onChange={(e) => setNewMarker({...newMarker, lon: e.target.value})}
              style={{ width: '100%', padding: '8px', marginBottom: '8px' }}
            />
            <select
              value={newMarker.type}
              onChange={(e) => setNewMarker({...newMarker, type: e.target.value})}
              style={{ width: '100%', padding: '8px' }}
            >
              <option value="default">Обычный</option>
              <option value="historic">Исторический</option>
              <option value="park">Парк</option>
              <option value="shop">Магазин</option>
              <option value="cafe">Кафе</option>
            </select>
          </div>
          <button
            onClick={handleAddMarker}
            style={{
              width: '100%',
              padding: '10px',
              backgroundColor: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            Добавить маркер
          </button>
        </div>

        <div>
          <h4>Список маркеров ({markers.length})</h4>
          <div style={{ maxHeight: '200px', overflowY: 'auto' }}>
            {markers.map(marker => (
              <div
                key={marker.id}
                style={{
                  padding: '10px',
                  marginBottom: '5px',
                  backgroundColor: selectedMarker?.id === marker.id ? '#e3f2fd' : 'white',
                  border: '1px solid #ddd',
                  borderRadius: '5px',
                  cursor: 'pointer',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center'
                }}
                onClick={() => {
                  setSelectedMarker(marker);
                  setCenter([marker.lat, marker.lon]);
                }}
              >
                <div>
                  <strong>{marker.title}</strong><br/>
                  <small>{marker.lat.toFixed(4)}, {marker.lon.toFixed(4)}</small>
                </div>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDeleteMarker(marker.id);
                  }}
                  style={{
                    padding: '5px 10px',
                    backgroundColor: '#dc3545',
                    color: 'white',
                    border: 'none',
                    borderRadius: '3px',
                    cursor: 'pointer'
                  }}
                >
                  ✕
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Карта */}
      <div style={{ flex: 1, height: '600px' }}>
        <YMaps>
          <Map 
            state={{ center, zoom: 10 }} 
            width="100%" 
            height="100%"
            onClick={handleMapClick}
          >
            {markers.map(marker => (
              <Placemark
                key={marker.id}
                geometry={[marker.lat, marker.lon]}
                options={{
                  iconLayout: 'default#image',
                  iconImageHref: getIconByType(marker.type),
                  iconImageSize: [36, 36],
                  iconImageOffset: [-18, -36],
                }}
                properties={{
                  hintContent: marker.title,
                  balloonContent: `
                    <div style="padding: 10px; min-width: 200px">
                      <h4 style="margin: 0 0 10px 0">${marker.title}</h4>
                      <p style="margin: 0 0 10px 0">Тип: ${marker.type}</p>
                      <div style="font-size: 12px; color: #666">
                        Координаты:<br/>
                        ${marker.lat.toFixed(6)}, ${marker.lon.toFixed(6)}
                      </div>
                      <button 
                        onclick="window.deleteMarker(${marker.id})"
                        style="margin-top: 10px; padding: 5px 10px; background: #dc3545; color: white; border: none; border-radius: 3px; cursor: pointer"
                      >
                        Удалить
                      </button>
                    </div>
                  `,
                }}
                onClick={() => setSelectedMarker(marker)}
              />
            ))}
          </Map>
        </YMaps>
      </div>
    </div>
  );
}

export default TestHome;
